import{bV as t,aL as a,u as o,G as l}from"./chunks/framework.BfzMay2U.js";const p=JSON.parse('{"title":"数据库权限","description":"","frontmatter":{"title":"数据库权限","date":"2022-06-22T23:26:10.000Z","categories":["Note"],"tags":["MySQL"]},"headers":[],"relativePath":"posts/sql-auth.md","filePath":"posts/sql-auth.md"}'),i={name:"posts/sql-auth.md"};function s(d,e,r,c,n,_){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="数据库权限" tabindex="-1">数据库权限 <a class="header-anchor" href="#数据库权限" aria-label="Permalink to &quot;数据库权限&quot;">​</a></h1><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>数据的权限主要分为六个层级：</p><ul><li>第一层是<code>登录验证</code>，验证失败则立即退出；</li><li>第二层的权限为<code>全局权限</code>，这个层级的权限覆盖整个数据库；</li><li>第三层的权限是<code>数据库级别的权限</code>，这个层级的权限是针对于某一个数据库的；</li><li>第四层级是<code>数据表级的权限</code>，这个层级的权限主要针对于数据表；</li><li>第五层权限是<code>字段级的权限</code>，主要针对于某一个字段的，需要注意的是字段级的权限需要依赖于第四层数据表级查看权限，没有数据表级查看权限，字段级权限无法生效；</li><li>最后一个<code>对象级权限</code>，这个权限主要是针对于存储函数和存储过程的，只有拥有该权限，才能够操作数据库存储函数或存储过程。</li></ul>',4)])])}const u=t(i,[["render",s]]);export{p as __pageData,u as default};
